namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId;
    private readonly List<Notification> _notifications;
    private readonly Lock _lock = new();

    public NotificationService()
    {
        _notifications =
        [
            new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
            new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-20)),
            new(3, "New feature: dark mode is available.", DateTime.UtcNow.AddMinutes(-10)),
        ];
        _nextId = _notifications.Count + 1;
    }

    /// <summary>Returns all notifications available at the time of the call.</summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>Returns only notifications created after the given timestamp.</summary>
    public List<Notification> GetNewSince(DateTime since)
    {
        lock (_lock)
        {
            // Simulate a new notification appearing roughly every 15 seconds.
            if (_notifications.Count == 0 || (DateTime.UtcNow - _notifications[^1].Timestamp).TotalSeconds >= 15)
            {
                var id = _nextId++;
                _notifications.Add(new(id, $"Background event #{id} occurred.", DateTime.UtcNow));
            }

            return _notifications.Where(n => n.Timestamp > since).ToList();
        }
    }
}

@page "/notifications"
@using NotificationsApp.Services
@inject NotificationService NotificationService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
</h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group mt-3">
        @foreach (var n in _notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@if (_isPolling)
{
    <p class="mt-3 text-success"><small>🔄 Live — polling for new notifications…</small></p>
}

@code {
    private List<Notification> _notifications = [];
    private CancellationTokenSource? _cts;
    private bool _isPolling;

    // Runs during prerender AND when the component becomes interactive.
    // On the first (prerender) call we load the initial data so it appears
    // in the server-rendered HTML.  The persist/restore pair below ensures
    // that when the component re-initialises for the interactive circuit we
    // reuse the same data instead of fetching it again.

    protected override void OnInitialized()
    {
        _notifications = NotificationService.GetAll();
    }

    // Called exactly once after the component is interactive in the browser.
    // Safe place to start long-running async work — this does NOT run during
    // the static SSR pass.
    protected override Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }

        return Task.CompletedTask;
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        _isPolling = true;
        await InvokeAsync(StateHasChanged);

        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            var since = _notifications.Count > 0
                ? _notifications.Max(n => n.Timestamp)
                : DateTime.MinValue;

            var newer = NotificationService.GetNewSince(since);
            if (newer.Count > 0)
            {
                _notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }

        _isPolling = false;
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

